    private void buttonDeleteActionPerformed(java.awt.event.ActionEvent evt) {// GEN-FIRST:event_buttonDeleteActionPerformed
        String main_display_content = jTextField1.getText();
        int length = main_display_content.length();
        String updated_string = main_display_content.substring(0, length - 1);

        if (updated_string.equals("")) {
            jTextField1.setText("0");
        } else {
            jTextField1.setText(updated_string);
        }
    }// GEN-LAST:event_buttonDeleteActionPerformed

