    private void buttonChangeSymbolActionPerformed(java.awt.event.ActionEvent evt) {// GEN-FIRST:event_buttonChangeSymbolActionPerformed
        String main_display_content = jTextField1.getText();
        String left_operator = main_display_content.substring(0, 1);
        String temp = main_display_content;
        int main_display_length = main_display_content.length();

        if (!main_display_content.equals("0")) {

            if (left_operator.equals("-")) {
                main_display_content = main_display_content.substring(1, main_display_length);
            } else {
                main_display_content = "-" + temp;
            }
        }

        jTextField1.setText(main_display_content);
    }// GEN-LAST:event_buttonChangeSymbolActionPerformed

    private void jTextField1KeyPressed(java.awt.event.KeyEvent evt) {// GEN-FIRST:event_jTextField1KeyPressed
        switch (evt.getKeyCode()) {
            case KeyEvent.VK_NUMPAD0:
                buttonZero.doClick();
                break;
            case KeyEvent.VK_NUMPAD1:
                buttonOne.doClick();
                break;
            case KeyEvent.VK_NUMPAD2:
                buttonTwo.doClick();
                break;
            case KeyEvent.VK_NUMPAD3:
                buttonThree.doClick();
                break;
            case KeyEvent.VK_NUMPAD4:
                buttonFour.doClick();
                break;
            case KeyEvent.VK_NUMPAD5:
                buttonFive.doClick();
                break;
            case KeyEvent.VK_NUMPAD6:
                buttonSix.doClick();
                break;
            case KeyEvent.VK_NUMPAD7:
                buttonSeven.doClick();
                break;
            case KeyEvent.VK_NUMPAD8:
                buttonEight.doClick();
                break;
            case KeyEvent.VK_NUMPAD9:
                buttonNine.doClick();
                break;
            case KeyEvent.VK_ADD:
                buttonAdd.doClick();
                break;
            case KeyEvent.VK_SUBTRACT:
                buttonSubtract.doClick();
                break;
            case KeyEvent.VK_MULTIPLY:
                buttonMultiply.doClick();
                break;
            case KeyEvent.VK_DIVIDE:
                buttonDivide.doClick();
                break;
            case KeyEvent.VK_DECIMAL:
                buttonPeriod.doClick();
                break;
            case KeyEvent.VK_BACK_SPACE:
                buttonDelete.doClick();
                break;
            case KeyEvent.VK_C:
                buttonClear.doClick();
                break;
            case KeyEvent.VK_ENTER:
                buttonEquals.doClick();
                break;
        }
    }// GEN-LAST:event_jTextField1KeyPressed

