    private void appendCharacter(String character) {
        String main_display_content = jTextField1.getText();

        if (after_equal) {
            jTextField1.setText(character);
            jTextField2.setText("");
            after_equal = false;
        } else if (character.equals(".") && !main_display_content.contains(".")) {
            jTextField1.setText(main_display_content + character);
        } else if (character.equals(".") && main_display_content.contains(".")) {
            // non fa nulla
        } else if (main_display_content.equals("0")) {
            jTextField1.setText(character);
        } else {
            jTextField1.setText(main_display_content + character);
        }
    }

    private void calculateAndUpdateTextFields(int result_destination, String key_pressed_operator) {
        TextFields TF = new TextFields(jTextField1.getText(), jTextField2.getText());
        Results R;

        if (TF.secondary_display_content.equals("")) {
            TF.main_display_content = parenthesisInator(TF.main_display_content);
            jTextField2.setText(TF.main_display_content + key_pressed_operator);
            jTextField1.setText("0");
        } else {
            R = handleOperation(TF, result_destination);

            if (result_destination == 0 && "=".equals(key_pressed_operator)) {
                updateTextFieldsWithResultOnMainDisplay(TF, R);
            } else {
                updateTextFieldsWithResultOnSecondaryDisplay(TF, R, key_pressed_operator);
            }

            jTextField1.setText(TF.main_display_content);
            jTextField2.setText(TF.secondary_display_content);

            History.saveToBuffer(R.first_value + R.OP.middle_operator + R.second_value + "=" + R.result);
        }
    }

    private void updateTextFieldsWithResultOnMainDisplay(TextFields TF, Results R) {
        String temp;

        if (after_equal) {
            R.first_value = parenthesisInator(R.first_value);
            R.second_value = parenthesisInator(R.second_value);
        } else {
            temp = R.first_value;
            R.first_value = parenthesisInator(R.second_value);
            R.second_value = parenthesisInator(temp);
        }

        TF.secondary_display_content = R.first_value + R.OP.middle_operator + R.second_value;
        TF.main_display_content = R.result;
    }

    private void updateTextFieldsWithResultOnSecondaryDisplay(TextFields TF, Results R, String key_pressed_operator) {
        if (R.OP.middle_operator_position == TF.secondary_display_content.length() - 1) { // quando è presente un solo
                                                                                          // valore nel campo di testo
                                                                                          // secondario
            TF.secondary_display_content = TF.secondary_display_content.substring(0, R.OP.middle_operator_position);
            TF.secondary_display_content += key_pressed_operator;
            TF.main_display_content = "0";
        } else if (after_equal) {
            TF.secondary_display_content = TF.main_display_content + key_pressed_operator;
            TF.main_display_content = "0";
        } else {
            R.first_value = parenthesisInator(R.first_value);
            R.second_value = parenthesisInator(R.second_value);

            TF.secondary_display_content = R.second_value + key_pressed_operator;
            TF.main_display_content = "0";
        }
    }

    private Results handleOperation(TextFields TF, int result_destination) {
        TF.secondary_display_content = deParenthesisInator(TF.secondary_display_content);
        MiddleOperator OP = new MiddleOperator(TF.secondary_display_content); // ottengo l'operatore tra i due numeri

        double main_display_value = Double.parseDouble(TF.main_display_content);
        double secondary_display_value;
        double result = 0;

        if (result_destination == 0) { // destinazione del risultato nel main display
            if (after_equal) {
                TF.secondary_display_content = TF.secondary_display_content.substring(OP.middle_operator_position + 1,
                        TF.secondary_display_content.length()); // prendo solo la parte dopo l'operatore
                secondary_display_value = Double.parseDouble(TF.secondary_display_content);
                result = calculate(OP.middle_operator, main_display_value, secondary_display_value);
            } else {
                TF.secondary_display_content = TF.secondary_display_content.substring(0, OP.middle_operator_position); // rimuovo
                                                                                                                       // l'operatore
                                                                                                                       // dal
                                                                                                                       // contenuto
                                                                                                                       // della
                                                                                                                       // stringa
                secondary_display_value = Double.parseDouble(TF.secondary_display_content);
                result = calculate(OP.middle_operator, secondary_display_value, main_display_value);
            }
        } else { // destinazione del risultato nel secondary display
            TF.secondary_display_content = TF.secondary_display_content.substring(0, OP.middle_operator_position); // rimuovo
                                                                                                                   // l'operatore
                                                                                                                   // dal
                                                                                                                   // contenuto
                                                                                                                   // della
                                                                                                                   // stringa
            secondary_display_value = Double.parseDouble(TF.secondary_display_content);
            secondary_display_value = calculate(OP.middle_operator, secondary_display_value, main_display_value);
        }

        return new Results(main_display_value, secondary_display_value, OP, result);
    }

    // metodo che aggiunge le parentesi al valore se ha segno negativo:
    private String parenthesisInator(String str_value) {
        String left_operator = str_value.substring(0, 1);

        if (left_operator.equals("-")) {
            str_value = "(" + str_value + ")";
        }

        return str_value;
    }

    // metodo che rimuove le parentesi al valore se presenti:
    private String deParenthesisInator(String str_value) {

        if (str_value.contains("(") || str_value.contains(")")) {
            str_value = str_value.replace("(", "");
            str_value = str_value.replace(")", "");
        }

        return str_value;
    }

    private double calculate(String operator, double first_value, double second_value) {
        switch (operator) {
            case "+":
                return first_value + second_value;
            case "-":
                return first_value - second_value;
            case "*":
                return first_value * second_value;
            case "÷":
                return first_value / second_value;
            case "%":
                return (first_value * second_value) / 100;
            default:
                System.out.println("[ERRORE]: Operatore non riconosciuto");
                return 0;
        }
    }

